function LGameSettings.InitGameSettings()
	local gameSettings = CardEHT.ManagerCenter.GameMgr.GameSettings

	LGameSettings.resMode = gameSettings.resMode
	LGameSettings.debugMode = gameSettings.debugMode
	LGameSettings.logEnable = gameSettings.logEnable
	LGameSettings.updateMode = gameSettings.updateMode
	LGameSettings.networkMode = gameSettings.networkMode
	LGameSettings.luaByteMode = gameSettings.luaByteMode
	LGameSettings.showFps = gameSettings.showFps
	LGameSettings.gameFrameRate = gameSettings.gameFrameRate

	local settingVars = gameSettings.gameSettingVars
	if settingVars then
		local iter = settingVars:GetEnumerator()
		while iter:MoveNext() do
			local varObj = iter.Current
			if varObj ~= nil then
				LGameSettings[varObj.varName] = varObj.varVal
			end
		end
	end

	DEBUG = checknumber(LGameSettings["Debug"])
	LOG_INFO_ENABLED = DEBUG >= 2
	LOG_WARN_ENABLED = DEBUG >= 1
	LOG_ERROR_ENABLED = DEBUG >= 0

	LXFW.LxLog.logEnabled = DEBUG >= 2

	LOG_TRACE = checkbool(LGameSettings["LogTrace"])
	ENABLE_PROTO_LOG = checkbool(LGameSettings["LogProto"])
	ENABLE_FIGHT_LOG = checkbool(LGameSettings["LogFight"])

	local urlList = {}
	if not string.isempty(LGameSettings.pf_url1) then
		table.insert(urlList, LGameSettings.pf_url1)
	end
	if not string.isempty(LGameSettings.pf_url2) then
		table.insert(urlList, LGameSettings.pf_url2)
	end
	LGameSettings.platformUrlList = urlList

	local updateList = {}
	if not string.isempty(LGameSettings.update_url1) then
		table.insert(updateList, LGameSettings.update_url1)
	end
	if not string.isempty(LGameSettings.update_url2) then
		table.insert(updateList, LGameSettings.update_url2)
	end
	LGameSettings.updateUrlList = updateList

	local pfDevStr = LGameSettings.pf_dev
	if not string.isempty(pfDevStr) then
		if (pfDevStr == "Dev") then
			LGameSettings.platformDev = true
		end
	end

	local pfErrorStr = LGameSettings["pf_err"]
	if not string.isempty(pfErrorStr) then
		LGameSettings.platformErr = true
	end
	local pfBugly = tonumber(LGameSettings["pf_bugly"]) or 0
	LGameSettings.platformBugly = pfBugly

	LGameSettings.platformId = tonumber(LGameSettings["pf_id"]) or 0
	LGameSettings.platformSdk = LGameSettings["platformName"] or ""
	LGameSettings.platformTitle = LGameSettings["platformSub"] or ""
	LGameSettings.platformChannelId = tonumber(LGameSettings["pf_channelid"]) or 0
	LGameSettings.platformFromId = tonumber(LGameSettings["pf_fromid"]) or 0

	LGameSettings.platformLoginPng = LGameSettings["pf_pnglogin"] or ""
	LGameSettings.platformLoadPng = LGameSettings["pf_pngload"] or ""
	LGameSettings.platformLoginPng_ver = LGameSettings["pf_pnglogin_ver"] or ""
	LGameSettings.platformLoadPng_ver = LGameSettings["pf_pngload_ver"] or ""

	LGameSettings.usePackageImage = toboolean(LGameSettings["usePackageImage"])

	LGameSettings.platformLogoPng = LGameSettings["pf_pnglogo"] or ""

	LGameSettings.platformDefaultLng = LGameSettings["lng"] or "zhcn"
	LGameSettings.showLogUpload = toboolean(LGameSettings["is_logupload"])
	LGameSettings.platformSpecial = tonumber(LGameSettings["pf_special"]) or 0


	if LOG_INFO_ENABLED then
		print("LGameSettings.platformDefaultLng = " ..LGameSettings.platformDefaultLng)
	end

	LGameSettings.platformGooglePack = tonumber(LGameSettings["pf_google_pack"]) or 0
	LGameSettings.platformRegion = tonumber(LGameSettings["pf_region"]) or 0

	LGameSettings.isWebGL = toboolean(LGameSettings["isWebGL"])
	LGameSettings.isNoSound = toboolean(LGameSettings["isNoSound"])
	LGameSettings.maxRecv = tonumber(LGameSettings["maxRecv"])

	LGameSettings.clearBundleCount = tonumber(LGameSettings.clearBundleCount)
	LGameSettings.clearBundleTotalCount = tonumber(LGameSettings.clearBundleTotalCount)
	LGameSettings.clearBundleInterval = tonumber(LGameSettings.clearBundleInterval) or 120


	if CS.IsWebGL() then
		if not string.isempty(LGameSettings["clearBundleMaxCount"]) then
			LGameSettings.bundleMaxCount = tonumber(LGameSettings["clearBundleMaxCount"])
		end

		if not string.isempty(LGameSettings["clearGcMaxCount"]) then
			LGameSettings.gcMaxCount = tonumber(LGameSettings["clearGcMaxCount"])
		end

		--if not string.isempty(LGameSettings["assetBundleMaxMemory"]) then
		--	LGameSettings.assetBundleMaxMemory = tonumber(LGameSettings["assetBundleMaxMemory"])
		--end

		if not string.isempty(LGameSettings["instantiateInterval"]) then
			LGameSettings.instantiateInterval = tonumber(LGameSettings["instantiateInterval"])
		end

		LGameSettings.highFrameRate = tonumber(LGameSettings["highFrameRate"]) or 60

		LGameSettings.gcAccumulateMaxCount = tonumber(LGameSettings["gcAccumulateMaxCount"]) or 0
		LGameSettings.checkGcCountInterval = tonumber(LGameSettings["checkGcCountInterval"]) or 1
		LGameSettings.isCheckGcCount = toboolean(LGameSettings["isCheckGcCount"])
		LGameSettings.isPrintGcCount = toboolean(LGameSettings["isPrintGcCount"])
		LGameSettings.printGcCountInterval = tonumber(LGameSettings["printGcCountInterval"]) or 1
		LGameSettings.freeTimeGcInterval = tonumber(LGameSettings["freeTimeGcInterval"]) or 0
		LGameSettings.isShowWebGLDebugBtn = toboolean(LGameSettings["isShowWebGLDebugBtn"])
		LGameSettings.isWs = toboolean(LGameSettings["isWs"])
		LGameSettings.isFrameInstantiate = toboolean(LGameSettings["isFrameInstantiate"])
		LGameSettings.autoReleaseTime = tonumber(LGameSettings["autoReleaseTime"]) or 180
		LGameSettings.isAutoRelease = toboolean(LGameSettings["isAutoRelease"])
		LGameSettings.isNotSceneRelease = toboolean(LGameSettings["isNotSceneRelease"])
		LGameSettings.isAndroidGc = toboolean(LGameSettings["isAndroidGc"])
		LGameSettings.isSetPixelRatio = toboolean(LGameSettings["isSetPixelRatio"])
		LGameSettings.isPauseNotClearBundleUnused = toboolean(LGameSettings["isPauseNotClearBundleUnused"])
		LGameSettings.isPauseForceClear = toboolean(LGameSettings["isPauseForceClear"])
		LGameSettings.isSubpackage = toboolean(LGameSettings["isSubpackage"], true)
		LGameSettings.isLoginAfter = toboolean(LGameSettings["isLoginAfter"], true)
		LGameSettings.isNotBootBackground = toboolean(LGameSettings["isNotBootBackground"], true)
		LGameSettings.isNotPreload = toboolean(LGameSettings["isNotPreload"])
		LGameSettings.isNotPreloadSubpackage = toboolean(LGameSettings["isNotPreloadSubpackage"])
		LGameSettings.isNotDownBackupFont = toboolean(LGameSettings["isNotDownBackupFont"])
		LGameSettings.isRunInBackground = toboolean(LGameSettings["isRunInBackground"])

		if LGameSettings.isRunInBackground then
			UnityEngine.Application.runInBackground = true
		end

		--if LOG_INFO_ENABLED then  --经过测试，这个后面才赋值，这个时候还是false
		if LGameSettings.platformDev then
			LxLog.logEnabled = true --打印开关是这个控制
			LOG_INFO_ENABLED = true
			gprint("LGameSettings.bundleMaxCount = ", LGameSettings.bundleMaxCount)
			gprint("LGameSettings.gcMaxCount = ", LGameSettings.gcMaxCount)
			gprint("LGameSettings.gcAccumulateMaxCount = ", LGameSettings.gcAccumulateMaxCount)
			gprint("LGameSettings.freeTimeGcInterval = ", LGameSettings.freeTimeGcInterval)
			gprint("LGameSettings.isShowWebGLDebugBtn = ", LGameSettings.isShowWebGLDebugBtn)
			gprint("LGameSettings.isWs = ", LGameSettings.isWs)
			gprint("LGameSettings.isFrameInstantiate = ", LGameSettings.isFrameInstantiate)
			gprint("LGameSettings.instantiateInterval = ", LGameSettings.instantiateInterval)
			gprint("LGameSettings.autoReleaseTime = ", LGameSettings.autoReleaseTime)
			gprint("LGameSettings.isAutoRelease = ", LGameSettings.isAutoRelease)
			gprint("LGameSettings.isNotSceneRelease = ", LGameSettings.isNotSceneRelease)
			gprint("LGameSettings.isSetPixelRatio = ", LGameSettings.isSetPixelRatio)
			gprint("LGameSettings.isPauseNotClearBundleUnused = ", LGameSettings.isPauseNotClearBundleUnused)
			gprint("LGameSettings.isPauseForceClear = ", LGameSettings.isPauseForceClear)
		end
	end

	return true
end

function LGameSettings.IsDev()
	local isDev = checkbool(LGameSettings.dev)
	return isDev
end

function LGameSettings.IsQueryHost()
	local isQueryHost = checknumber(LGameSettings.queryHost) > 0
	return isQueryHost
end

return LGameSettings